import{_ as e,c as t,o as a,b as n}from"./app.ad5aee2a.js";const _='{"title":"Pitch","description":"","frontmatter":{"title":"Pitch","subtitle":"Explorations of the acoustic frequency domain","date":"2021-09-30T00:00:00.000Z"},"headers":[],"relativePath":"apps/pitch/index.md"}',i={},o=n('<p>Find any giver pitch on any giver instrument with the colorful <a href="./tuner/">Tuner</a> that analyzes incoming audio and exactly shows you the main pitch.</p><p>Or you may start plotting the detected pitch an endless <a href="./roll/">Pitch Roll</a> and have fun drawing ups and downs with sound. Much more complex and information rich plot is produced by the <a href="./spectrogram/">Spectrograph</a> that draws FFT frequency content of any incoming audio.</p><p>We can not only analyze, but produce different pitches with this web-site. There&#39;s a traditional <a href="./drone/">Drone machine</a> that will generate a rich in upper harmonics sound of any desired pitch and a fifth above it to generate a pleasant background for vocal practice and instrument tuning.</p><p>If you want to combine more simultaneous drone pitches - feel free to browse the <a href="./table/">Pitch table</a> of all audible audio frequencies and beyond! And in case you&#39;ll need to try organizing those pithes in loops in time - that&#39;s what the <a href="./grid/">Pitch grid</a> is designed for.</p>',4),r=[o];function c(s,d,h,p,l,u){return a(),t("div",null,r)}var m=e(i,[["render",c]]);export{_ as __pageData,m as default};
